214	    private String areaOf(String k) {
215	        k = k == null ? "" : k.toLowerCase();
216	        if (k.contains("mysql") || k.contains("sql") || k.contains("redis") || k.contains("database")) return "db";
217	        if (k.contains("vue") || k.contains("react") || k.contains("front") || k.contains("js")) return "frontend";
218	        if (k.contains("docker") || k.contains("k8") || k.contains("devops") || k.contains("deploy")) return "devops";
219	        if (k.contains("spring") || k.contains("java") || k.contains("mybatis") || k.contains("api")) return "backend";
220	        return "algorithm";
221	    }
222	
223	    private String areaName(String key) {
224	        return switch (key) {
225	            case "db" -> "数据库与缓存";
226	            case "frontend" -> "前端工程";
227	            case "backend" -> "后端开发";
228	            case "devops" -> "DevOps 与部署";
229	            default -> "算法与数据结构";
230	        };
231	    }
232	
233	    private String areaSuggestion(String key, int score) {
234	        if (score >= 80) return "掌握较好，建议通过项目实战巩固";
235	        return switch (key) {
236	            case "db" -> "完成数据库优化实操并复习缓存策略";
237	            case "frontend" -> "完成 1 次组件重构并补齐性能优化清单";
238	            case "backend" -> "完成 1 个鉴权接口与异常处理优化";
239	            case "devops" -> "完成一次 Docker Compose 全链路部署";
240	            default -> "完成 3 道算法题并复盘";
241	        };
242	    }
243	
244	    private String planOf(String key) {
245	        return switch (key) {
246	            case "db" -> "完成 2 次 SQL 优化练习并总结索引命中规则";
247	            case "frontend" -> "完成 1 次组件重构并补齐性能优化清单";
248	            case "backend" -> "完成 1 个鉴权接口和 1 个异常处理优化";
249	            case "devops" -> "完成本地一键部署并验证回滚流程";
250	            default -> "完成 3 道算法题并沉淀解题模板";
251	        };
252	    }
253	
254	    private void addRow(PdfPTable table, String leftText, String rightText, Font font) {
255	        PdfPCell left = new PdfPCell(new Phrase(leftText, font));
256	        left.setPadding(8); table.addCell(left);
257	        PdfPCell right = new PdfPCell(new Phrase(rightText, font));
258	        right.setPadding(8); right.setHorizontalAlignment(Element.ALIGN_RIGHT); table.addCell(right);
259	    }
260	}
