        if (paths.isEmpty()) {
            return List.of(
                    new WeakAreaVO("db", "数据库与缓存", 40, "完成 2 次 SQL 优化练习"),
                    new WeakAreaVO("algorithm", "算法与数据结构", 45, "每周完成 3 道中等题"),
                    new WeakAreaVO("backend", "后端开发", 50, "补齐鉴权与异常处理实践")
